/**
 * Unit tests for tool-invocation-linter PreToolUse hook (#1883 framework).
 *
 * Covers Layer 1 (per the plan): pure logic, mocked HookInput.
 * Layer 2 (registry-coverage gate) lives in tool-invocation-rules.coverage.test.ts.
 *
 * What we assert:
 *   1.  Matching predicate fires on Agent + isolation:'worktree'
 *   2.  Mismatched predicate does NOT fire on Agent + isolation:'file'
 *   3.  Missing isolation field is silent
 *   4.  Different tool_name (Bash) is silent
 *   5.  Other params alongside isolation still trigger
 *   6.  message contains see-also link (M167.4, #1883)
 *   7.  severity=warn → continue:true (non-blocking)
 *   8.  Empty registry → silent success
 *   9.  Unknown tool_name → silent success (no false positive)
 *   10. Corrupt rule (throwing predicate) → skipped, no crash
 *   11. Multiple matching rules → all messages concatenated
 */

import { describe, it, expect, vi, beforeEach } from 'vitest';
import { mockCommonBasic } from '../fixtures/mock-common.js';

vi.mock('../../lib/common.js', () => mockCommonBasic());

import { toolInvocationLinter } from '../../pretool/tool-invocation-linter.js';
import type { HookInput } from '../../types.js';
import { createTestContext } from '../fixtures/test-context.js';

function makeInput(overrides: Partial<HookInput> = {}): HookInput {
  return {
    tool_name: 'Agent',
    session_id: 'test-session',
    tool_input: {},
    ...overrides,
  };
}

let testCtx: ReturnType<typeof createTestContext>;

describe('toolInvocationLinter', () => {
  beforeEach(() => {
    testCtx = createTestContext();
    vi.clearAllMocks();
  });

  // ─── 1. Matching predicate fires ────────────────────────────────
  it('fires on Agent + isolation:"worktree" (seed rule #1883)', () => {
    const result = toolInvocationLinter(
      makeInput({
        tool_name: 'Agent',
        tool_input: { subagent_type: 'general-purpose', isolation: 'worktree' },
      }),
      testCtx,
    );

    expect(result.continue).toBe(true);
    const ctx = result.hookSpecificOutput?.additionalContext ?? result.systemMessage ?? '';
    expect(ctx).toContain('agent-isolation-worktree');
    expect(ctx).toContain('worktree');
  });

  // ─── 2. Mismatched predicate is silent ──────────────────────────
  it('does NOT fire on Agent + isolation:"file"', () => {
    const result = toolInvocationLinter(
      makeInput({
        tool_name: 'Agent',
        tool_input: { isolation: 'file' },
      }),
      testCtx,
    );

    expect(result.continue).toBe(true);
    expect(result.suppressOutput).toBe(true);
  });

  // ─── 3. Missing isolation field is silent ───────────────────────
  it('does NOT fire on Agent without isolation field', () => {
    const result = toolInvocationLinter(
      makeInput({ tool_name: 'Agent', tool_input: { subagent_type: 'general-purpose' } }),
      testCtx,
    );

    expect(result.continue).toBe(true);
    expect(result.suppressOutput).toBe(true);
  });

  // ─── 4. Different tool_name is silent ───────────────────────────
  it('does NOT fire on Bash even if input has isolation:"worktree" string', () => {
    const result = toolInvocationLinter(
      makeInput({
        tool_name: 'Bash',
        tool_input: { command: 'echo isolation worktree' },
      }),
      testCtx,
    );

    expect(result.continue).toBe(true);
    expect(result.suppressOutput).toBe(true);
  });

  // ─── 5. Other params present alongside isolation still trigger ──
  it('still fires when isolation is mixed with other params (no shielding)', () => {
    const result = toolInvocationLinter(
      makeInput({
        tool_name: 'Agent',
        tool_input: {
          subagent_type: 'general-purpose',
          isolation: 'worktree',
          model: 'opus',
          description: 'do thing',
        },
      }),
      testCtx,
    );

    const ctx = result.hookSpecificOutput?.additionalContext ?? result.systemMessage ?? '';
    expect(ctx).toContain('agent-isolation-worktree');
  });

  // ─── 6. message contains see-also link ──────────────────────────
  it('includes see-also link (M167.4 / #1883) in the advisory', () => {
    const result = toolInvocationLinter(
      makeInput({
        tool_name: 'Agent',
        tool_input: { isolation: 'worktree' },
      }),
      testCtx,
    );

    const ctx = result.hookSpecificOutput?.additionalContext ?? result.systemMessage ?? '';
    expect(ctx).toMatch(/parallel-primitives|#1883/);
  });

  // ─── 7. severity=warn → continue:true ───────────────────────────
  it('is non-blocking for severity=warn (continue:true)', () => {
    const result = toolInvocationLinter(
      makeInput({
        tool_name: 'Agent',
        tool_input: { isolation: 'worktree' },
      }),
      testCtx,
    );

    expect(result.continue).toBe(true);
    expect(result.stopReason).toBeUndefined();
  });

  // ─── 8 & 9: degenerate inputs ──────────────────────────────────
  it('handles missing tool_name gracefully', () => {
    // tool_name is typed string|undefined in HookInput, so no ts-expect-error.
    const result = toolInvocationLinter(makeInput({ tool_name: undefined as unknown as string }), testCtx);
    expect(result.continue).toBe(true);
    expect(result.suppressOutput).toBe(true);
  });

  it('handles unknown tool_name as silent success', () => {
    const result = toolInvocationLinter(
      makeInput({ tool_name: 'NotARealTool', tool_input: { isolation: 'worktree' } }),
      testCtx,
    );
    expect(result.continue).toBe(true);
    expect(result.suppressOutput).toBe(true);
  });
});

// ─── safelyMatches contract ─────────────────────────────────────
import { safelyMatches, type ToolInvocationRule } from '../../lib/tool-invocation-rules.js';

describe('safelyMatches', () => {
  it('returns true when predicate returns true', () => {
    const rule: ToolInvocationRule = {
      id: 'x',
      tool_name: 'Agent',
      predicate: () => true,
      severity: 'warn',
      message: 'm',
      see: 's',
    };
    expect(safelyMatches(rule, {})).toBe(true);
  });

  it('returns false when predicate throws (defensive against buggy rules)', () => {
    const rule: ToolInvocationRule = {
      id: 'crashy',
      tool_name: 'Agent',
      predicate: () => {
        throw new Error('rule bug');
      },
      severity: 'warn',
      message: 'm',
      see: 's',
    };
    expect(safelyMatches(rule, {})).toBe(false);
  });
});
